package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class LineItemTest {

  @Test
  void testGetName_returnsCorrectName() throws Exception {
    String expectedName = "TestItem";
    int quantity = 5;
    long priceInMicros = 100000L;
    String currencyCode = "USD";

    // Use the class directly instead of Class.forName()
    Class<LineItem> clazz = LineItem.class;
    Constructor<LineItem> constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance(expectedName, quantity, priceInMicros, currencyCode);

    String actualName = (String) clazz.getMethod("getName").invoke(lineItem);

    assertEquals(expectedName, actualName);
  }
}
